import { Marker, Popup } from "react-leaflet";
import L from "leaflet";

const planeIcon = new L.Icon({
  iconUrl: "https://cdn-icons-png.flaticon.com/512/34/34627.png",
  iconSize: [35, 35],
});

export default function PlaneMarker({ position, flightData }) {
  if (!flightData) return null;

  return (
    <Marker position={position} icon={planeIcon}>
      <Popup>
        <b>{flightData.callsign}</b><br />
        Alt: {Math.round(flightData.altitude)}<br />
        Speed: {Math.round(flightData.velocity)}
      </Popup>
    </Marker>
  );
}
